/* ===== FILE SEEK FUNCTIONS ===== */

StradaValue* strada_seek(StradaValue *fh, StradaValue *offset, StradaValue *whence) {
    if (!fh || STRADA_IS_TAGGED_INT(fh) || fh->type != STRADA_FILEHANDLE || !fh->value.fh) {
        return strada_new_int(-1);
    }
    int w;
    /* Perl idiomatic calls pass `SEEK_END` etc. as a bareword. perla's
     * bareword codegen emits a STRADA_STR literal when the name is
     * known only at runtime as a constant sub (POSIX / Fcntl). Map
     * those names to the matching whence constant so
     * `seek($fh, 0, SEEK_END)` works even without parens. */
    if (whence && !STRADA_IS_TAGGED_INT(whence) && whence->type == STRADA_STR && whence->value.pv) {
        if (strcmp(whence->value.pv, "SEEK_SET") == 0) w = SEEK_SET;
        else if (strcmp(whence->value.pv, "SEEK_CUR") == 0) w = SEEK_CUR;
        else if (strcmp(whence->value.pv, "SEEK_END") == 0) w = SEEK_END;
        else w = (int)strada_to_int(whence);
    } else {
        w = (int)strada_to_int(whence);
    }
    int seek_whence = SEEK_SET;
    if (w == 1) seek_whence = SEEK_CUR;
    else if (w == 2) seek_whence = SEEK_END;

    int result = fseek(fh->value.fh, strada_to_int(offset), seek_whence);
    return strada_new_int(result == 0 ? 1 : 0);
}

StradaValue* strada_tell(StradaValue *fh) {
    if (!fh || STRADA_IS_TAGGED_INT(fh) || fh->type != STRADA_FILEHANDLE || !fh->value.fh) {
        return strada_new_int(-1);
    }
    return strada_new_int(ftell(fh->value.fh));
}

StradaValue* strada_rewind(StradaValue *fh) {
    if (!fh || STRADA_IS_TAGGED_INT(fh) || fh->type != STRADA_FILEHANDLE || !fh->value.fh) {
        return strada_new_int(0);
    }
    rewind(fh->value.fh);
    return strada_new_int(1);
}

StradaValue* strada_eof(StradaValue *fh) {
    /* Perl convention: eof() returns 1 for true, "" (empty string) for
     * false. Both are correct boolean values, but they stringify
     * differently — `print "eof=", eof($fh)` shows `eof=` (perl) vs
     * `eof=0` (older perla). Empty string matches Perl exactly. */
    if (!fh || STRADA_IS_TAGGED_INT(fh) || fh->type != STRADA_FILEHANDLE || !fh->value.fh) {
        return strada_new_int(1);
    }
    FILE *fp = fh->value.fh;
    /* feof() only flips after a read fails, not when the position is at
     * end-of-file. Perl's eof() peeks a byte to find out. Without this,
     * slurping all content with `do { local $/; <$fh> }` left feof
     * still false and `eof($fh)` returned 0 even though every reader
     * idiom would say we're done. Mirror Perl by peeking + ungetc. */
    if (feof(fp)) return strada_new_int(1);
    int c = fgetc(fp);
    if (c == EOF) return strada_new_int(1);
    ungetc(c, fp);
    return strada_new_str("");
}

StradaValue* strada_flush(StradaValue *fh) {
    if (!fh || STRADA_IS_TAGGED_INT(fh) || fh->type != STRADA_FILEHANDLE || !fh->value.fh) {
        return strada_new_int(0);
    }
    return strada_new_int(fflush(fh->value.fh) == 0 ? 1 : 0);
}

/* core::autoflush(FH, BOOL) — toggle unbuffered writes on a FILEHANDLE.
 * Enabling drops the FILE*'s libc buffer (setvbuf _IONBF) so every byte
 * flushes immediately, matching perl `$|=1` semantics where partial-line
 * output appears in real time. Disabling restores the libc default
 * (_IOFBF block buffering). Returns 1 on success, 0 if fh isn't a real
 * FILEHANDLE. */
StradaValue* strada_autoflush(StradaValue *fh, StradaValue *flag) {
    if (!fh || STRADA_IS_TAGGED_INT(fh) || fh->type != STRADA_FILEHANDLE || !fh->value.fh) {
        return strada_new_int(0);
    }
    int enable = (int)strada_to_int(flag);
    if (enable) {
        setvbuf(fh->value.fh, NULL, _IONBF, 0);
    } else {
        setvbuf(fh->value.fh, NULL, _IOFBF, BUFSIZ);
    }
    return strada_new_int(1);
}

/* ===== DNS/HOSTNAME FUNCTIONS ===== */

StradaValue* strada_gethostbyname(StradaValue *hostname_val) {
    char _tb[256];
    const char *hostname = strada_to_str_buf(hostname_val, _tb, sizeof(_tb));
    struct hostent *he = gethostbyname(hostname);
    if (!he) {
        return strada_new_undef();
    }

    /* Return the first IPv4 address as a string */
    if (he->h_addr_list[0]) {
        char *addr = inet_ntoa(*(struct in_addr*)he->h_addr_list[0]);
        return strada_new_str(addr);
    }
    return strada_new_undef();
}

StradaValue* strada_gethostbyname_all(StradaValue *hostname_val) {
    char _tb[256];
    const char *hostname = strada_to_str_buf(hostname_val, _tb, sizeof(_tb));
    struct hostent *he = gethostbyname(hostname);
    if (!he) {
        return strada_new_undef();
    }

    /* Return all IPv4 addresses as an array */
    StradaValue *result = strada_new_array();
    for (int i = 0; he->h_addr_list[i]; i++) {
        char *addr = inet_ntoa(*(struct in_addr*)he->h_addr_list[i]);
        strada_array_push_take(result->value.av, strada_new_str(addr));
    }
    return result;
}

StradaValue* strada_gethostname(void) {
    char hostname[256];
    if (gethostname(hostname, sizeof(hostname)) == 0) {
        return strada_new_str(hostname);
    }
    return strada_new_undef();
}

StradaValue* strada_getaddrinfo_first(StradaValue *hostname_val, StradaValue *service_val) {
    char _tb[256];
    const char *hostname = strada_to_str_buf(hostname_val, _tb, sizeof(_tb));
    char _tb2[256];
    const char *service = strada_to_str_buf(service_val, _tb2, sizeof(_tb2));

    struct addrinfo hints, *res;
    memset(&hints, 0, sizeof(hints));
    hints.ai_family = AF_UNSPEC;        /* IPv4 or IPv6 */
    hints.ai_socktype = SOCK_STREAM;

    int status = getaddrinfo(hostname, service[0] ? service : NULL, &hints, &res);
    if (status != 0) {
        return strada_new_undef();
    }

    char ipstr[INET6_ADDRSTRLEN];
    ipstr[0] = '\0';
    if (res->ai_family == AF_INET6) {
        struct sockaddr_in6 *ipv6 = (struct sockaddr_in6 *)res->ai_addr;
        inet_ntop(AF_INET6, &(ipv6->sin6_addr), ipstr, sizeof(ipstr));
    } else {
        struct sockaddr_in *ipv4 = (struct sockaddr_in *)res->ai_addr;
        inet_ntop(AF_INET, &(ipv4->sin_addr), ipstr, sizeof(ipstr));
    }

    freeaddrinfo(res);
    return strada_new_str(ipstr);
}

/* ===== PATH FUNCTIONS ===== */

StradaValue* strada_realpath(StradaValue *path_val) {
    char _tb[PATH_MAX];
    const char *path = strada_to_str_buf(path_val, _tb, sizeof(_tb));
    char resolved[PATH_MAX];

    char *result = realpath(path, resolved);
    if (result) {
        return strada_new_str(resolved);
    }
    return strada_new_undef();
}

/* Alias for the FROZEN bootstrap compiler: its builtin table accepts
 * core::/sys::realpath (so Semantic passes) but it predates the codegen
 * mapping to strada_realpath, so it emits a literal sys_realpath() call.
 * Without this alias, any compiler-source use of core::realpath fails the
 * stage-1 link with "undefined reference to sys_realpath". */
StradaValue* sys_realpath(StradaValue *path_val) {
    return strada_realpath(path_val);
}

/* Same frozen-bootstrap alias story for core::mkdir (used by the
 * import_object probe-result cache in Parser.strada). */
StradaValue* sys_mkdir(StradaValue *path_val, StradaValue *mode_val) {
    return strada_mkdir(path_val, mode_val);
}

StradaValue* strada_dirname(StradaValue *path_val) {
    char *path = strada_to_str(path_val);
    char *dir = dirname(path);
    StradaValue *result = strada_new_str(dir);
    free(path);
    return result;
}

StradaValue* strada_basename(StradaValue *path_val) {
    char *path = strada_to_str(path_val);
    char *base = basename(path);
    StradaValue *result = strada_new_str(base);
    free(path);
    return result;
}

/* Expand csh-style braces in `pat` into a NULL-terminated list of new
 * strings. Caller frees each entry + the array. `{a,b}.txt` → ["a.txt",
 * "b.txt"]. Handles nesting and missing braces (returns pat as-is). */
static char** strada_brace_expand(const char *pat, size_t *count_out) {
    *count_out = 0;
    /* Find the first unnested `{` that has a matching `}` with at least
     * one `,` inside. If none, return pat as single result. */
    const char *open = NULL;
    int depth = 0;
    for (const char *q = pat; *q; q++) {
        if (*q == '\\' && q[1]) { q++; continue; }
        if (*q == '{') {
            if (depth == 0) { open = q; }
            depth++;
        } else if (*q == '}') {
            depth--;
        }
    }
    if (!open) {
        char **out = (char**)malloc(2 * sizeof(char*));
        if (!out) return NULL;
        out[0] = strdup(pat);
        out[1] = NULL;
        *count_out = 1;
        return out;
    }
    /* Find matching `}` for `open`. */
    const char *close = NULL;
    depth = 0;
    for (const char *q = open; *q; q++) {
        if (*q == '\\' && q[1]) { q++; continue; }
        if (*q == '{') { depth++; }
        else if (*q == '}') {
            depth--;
            if (depth == 0) { close = q; break; }
        }
    }
    if (!close) {
        char **out = (char**)malloc(2 * sizeof(char*));
        if (!out) return NULL;
        out[0] = strdup(pat);
        out[1] = NULL;
        *count_out = 1;
        return out;
    }
    /* Split content between open+1 and close on top-level commas. */
    size_t prefix_len = (size_t)(open - pat);
    size_t suffix_len = strlen(close + 1);
    /* Collect parts. */
    size_t parts_cap = 8, parts_n = 0;
    const char **part_starts = (const char**)malloc(parts_cap * sizeof(const char*));
    size_t *part_lens = (size_t*)malloc(parts_cap * sizeof(size_t));
    if (!part_starts || !part_lens) {
        free(part_starts); free(part_lens);
        char **out = (char**)malloc(2 * sizeof(char*));
        if (!out) return NULL;
        out[0] = strdup(pat);
        out[1] = NULL;
        *count_out = 1;
        return out;
    }
    const char *seg = open + 1;
    depth = 0;
    for (const char *q = open + 1; q <= close; q++) {
        if (q == close || (*q == ',' && depth == 0)) {
            if (parts_n >= parts_cap) {
                parts_cap *= 2;
                part_starts = (const char**)sr_xrealloc((void*)part_starts, parts_cap * sizeof(const char*));
                part_lens = (size_t*)sr_xrealloc(part_lens, parts_cap * sizeof(size_t));
            }
            part_starts[parts_n] = seg;
            part_lens[parts_n] = (size_t)(q - seg);
            parts_n++;
            seg = q + 1;
        } else if (*q == '\\' && q[1]) { q++; }
        else if (*q == '{') { depth++; }
        else if (*q == '}') { depth--; }
    }
    if (parts_n < 2) {
        free(part_starts); free(part_lens);
        char **out = (char**)malloc(2 * sizeof(char*));
        if (!out) return NULL;
        out[0] = strdup(pat);
        out[1] = NULL;
        *count_out = 1;
        return out;
    }
    /* For each part, recursively expand: prefix + part + suffix. */
    size_t out_cap = parts_n * 2, out_n = 0;
    char **out = (char**)malloc((out_cap + 1) * sizeof(char*));
    if (!out) { free(part_starts); free(part_lens); return NULL; }
    for (size_t i = 0; i < parts_n; i++) {
        size_t sub_len = prefix_len + part_lens[i] + suffix_len + 1;
        char *sub = (char*)malloc(sub_len);
        if (!sub) continue;
        memcpy(sub, pat, prefix_len);
        memcpy(sub + prefix_len, part_starts[i], part_lens[i]);
        memcpy(sub + prefix_len + part_lens[i], close + 1, suffix_len);
        sub[prefix_len + part_lens[i] + suffix_len] = 0;
        size_t inner_count = 0;
        char **inner = strada_brace_expand(sub, &inner_count);
        free(sub);
        if (!inner) continue;
        for (size_t j = 0; j < inner_count; j++) {
            if (out_n >= out_cap) {
                out_cap *= 2;
                out = (char**)realloc(out, (out_cap + 1) * sizeof(char*));
            }
            out[out_n++] = inner[j];
        }
        free(inner);
    }
    free(part_starts);
    free(part_lens);
    out[out_n] = NULL;
    *count_out = out_n;
    return out;
}

/* Detect if a pattern contains any unescaped glob metacharacter. */
static int strada_pattern_has_meta(const char *pat) {
    for (const char *q = pat; *q; q++) {
        if (*q == '\\' && q[1]) { q++; continue; }
        if (*q == '*' || *q == '?' || *q == '[' || *q == '{') return 1;
    }
    return 0;
}

StradaValue* strada_glob(StradaValue *pattern_val) {
    char _tb[PATH_MAX];
    const char *pattern = strada_to_str_buf(pattern_val, _tb, sizeof(_tb));
    StradaValue *arr = strada_new_array();

    /* Perl's glob splits on whitespace into multiple patterns and unions
     * the results. POSIX glob() takes a single pattern; iterate per
     * whitespace-separated chunk and accumulate. */
    const char *p = pattern;
    int flags = GLOB_TILDE;
    while (*p) {
        while (*p == ' ' || *p == '\t') p++;
        if (!*p) break;
        const char *start = p;
        while (*p && *p != ' ' && *p != '\t') p++;
        size_t len = (size_t)(p - start);
        if (len == 0) continue;
        char one[PATH_MAX];
        if (len >= sizeof(one)) len = sizeof(one) - 1;
        memcpy(one, start, len);
        one[len] = 0;

        /* Perl's csh-style: brace expansion is purely textual, NOT
         * filesystem-driven. `{a,b,c}.txt` returns a.txt b.txt c.txt
         * even when none exist. Expand braces manually, then glob each
         * expansion for filesystem matches (with `*`/`?`/`[` etc.),
         * or pass through the literal when no glob meta remain. */
        size_t expanded_count = 0;
        char **expanded = strada_brace_expand(one, &expanded_count);
        if (!expanded) continue;
        for (size_t ei = 0; ei < expanded_count; ei++) {
            const char *one_pat = expanded[ei];
            if (strada_pattern_has_meta(one_pat)) {
                glob_t gb;
                memset(&gb, 0, sizeof(gb));
                int rc = glob(one_pat, flags, NULL, &gb);
                if (rc == 0) {
                    for (size_t i = 0; i < gb.gl_pathc; i++) {
                        strada_array_push_take(arr->value.av, strada_new_str(gb.gl_pathv[i]));
                    }
                }
                globfree(&gb);
            } else {
                /* No glob meta — Perl returns the literal text. */
                strada_array_push_take(arr->value.av, strada_new_str(one_pat));
            }
            free(expanded[ei]);
        }
        free(expanded);
    }
    return arr;
}

StradaValue* strada_fnmatch(StradaValue *pattern_val, StradaValue *string_val) {
    char _tb[PATH_MAX];
    const char *pattern = strada_to_str_buf(pattern_val, _tb, sizeof(_tb));
    char _tb2[PATH_MAX];
    const char *string = strada_to_str_buf(string_val, _tb2, sizeof(_tb2));

    int result = fnmatch(pattern, string, FNM_PATHNAME);
    return strada_new_int(result == 0 ? 1 : 0);
}

/* File extension helper */
StradaValue* strada_file_ext(StradaValue *path_val) {
    char _tb[PATH_MAX];
    const char *path = strada_to_str_buf(path_val, _tb, sizeof(_tb));
    const char *dot = strrchr(path, '.');
    if (!dot || dot == path) {
        return strada_new_str("");
    }
    return strada_new_str(dot + 1);
}

/* Join path components */
StradaValue* strada_path_join(StradaValue *parts_val) {
    /* Guard before reading ->type: parts_val may be NULL or a tagged-int. */
    if (!parts_val || STRADA_IS_TAGGED_INT(parts_val)) return strada_new_undef();
    /* Handle both arrays and references to arrays */
    StradaValue *arr = parts_val;
    if (parts_val->type == STRADA_REF) {
        arr = parts_val->value.rv;
    }
    if (arr->type != STRADA_ARRAY) {
        return strada_new_undef();
    }

    StradaArray *av = arr->value.av;
    size_t len = av->size;
    if (len == 0) {
        return strada_new_str("");
    }

    /* Pre-convert all strings and calculate total length */
    char **strs = malloc(len * sizeof(char*));
    size_t *slens = malloc(len * sizeof(size_t));
    if (!strs || !slens) {
        free(strs); free(slens);
        return strada_new_str("");
    }
    size_t total = 0;
    for (size_t i = 0; i < len; i++) {
        StradaValue *part = strada_array_get(av, i);
        strs[i] = strada_to_str(part);
        slens[i] = strlen(strs[i]);
        if (total > SIZE_MAX - slens[i] - 1) {
            for (size_t j = 0; j <= i; j++) free(strs[j]);
            free(strs); free(slens);
            return strada_new_str("");
        }
        total += slens[i] + 1;  /* +1 for possible '/' */
    }

    char *result = malloc(total + 1);
    if (!result) {
        for (size_t i = 0; i < len; i++) free(strs[i]);
        free(strs); free(slens);
        return strada_new_str("");
    }
    size_t result_len = 0;
    result[0] = '\0';

    for (size_t i = 0; i < len; i++) {
        /* Add '/' if we already have content and it doesn't end in '/' */
        if (result_len > 0 && result[result_len - 1] != '/') {
            result[result_len++] = '/';
        }
        memcpy(result + result_len, strs[i], slens[i]);
        result_len += slens[i];
        free(strs[i]);
    }
    result[result_len] = '\0';
    free(strs);
    free(slens);

    StradaValue *ret = strada_new_str(result);
    free(result);
    return ret;
}

